const generateDates = () => {
  const dates = [];
  const days = ['So', 'Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa'];
  const now = new Date();
  for (let i = 0; i < 30; i++) {
    const d = new Date();
    d.setDate(now.getDate() + i);
    dates.push({
      dayLabel: days[d.getDay()],
      dateStr: d.toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit' }),
      fullDate: d.toISOString().split('T')[0]
    });
  }
  return dates;
};

