            Tickets
          </a>
        </div>

        {/* Mobile toggle */}
        <button 
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          className="md:hidden text-white p-2 outline-none"
          aria-label="Menu"
        >
          <div className="w-6 h-5 flex flex-col justify-between">
            <span className={`w-full h-0.5 bg-white transition-all duration-300 ${isMobileMenuOpen ? 'rotate-45 translate-y-2.5' : ''}`}></span>
            <span className={`w-full h-0.5 bg-white transition-all duration-300 ${isMobileMenuOpen ? 'opacity-0' : ''}`}></span>
            <span className={`w-full h-0.5 bg-white transition-all duration-300 ${isMobileMenuOpen ? '-rotate-45 -translate-y-2' : ''}`}></span>
          </div>
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      <div className={`md:hidden fixed inset-x-0 top-[72px] bottom-0 bg-[#1d3a28] z-40 transition-all duration-500 overflow-y-auto ${
        isMobileMenuOpen ? 'translate-x-0 opacity-100' : 'translate-x-full opacity-0'
      }`}>
        <div className="flex flex-col space-y-8 px-8 py-12">
          {NAVIGATION.map((link) => (
            <div key={link.label} className="flex flex-col space-y-4">
              <a 
                href={`#${link.href}`}
                onClick={closeMenu}
                className="text-white text-3xl font-display font-bold hover:text-[#7cb342] transition-colors"
              >
                {link.label}
              </a>
              {link.dropdown && (
                <div className="flex flex-col space-y-3 pl-4 border-l-2 border-[#7cb342]/30">
                  {link.dropdown.map(item => (
                    <a 
                      key={item.label}
                      href={`#${item.href}`}
                      onClick={closeMenu}
                      className="text-white/60 hover:text-white transition-colors text-lg"
                    >
                      {item.label}
                    </a>
                  ))}
                </div>
              )}
            </div>
          ))}
          <div className="pt-8">
            <a 
              href="#/weekly" 
              onClick={closeMenu}
              className="block w-full text-center bg-[#7cb342] text-white py-4 rounded-2xl font-bold uppercase tracking-widest"
            >
              Tickets Buchen
            </a>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

